using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddChatClient(chatClientBuilder =>
    chatClientBuilder.UseOpenAIChatClient(
        builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18"));

builder.Services.AddSingleton<NoteStore>();
builder.Services.AddSingleton<WebSearchService>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteStore = host.Services.GetRequiredService<NoteStore>();
var webSearch = host.Services.GetRequiredService<WebSearchService>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up")] string query) => webSearch.SearchAsync(query),
        "web_search",
        "Searches the web for information on a given query. Returns a list of relevant snippets."),

    AIFunctionFactory.Create(
        ([Description("Title for the note")] string title,
         [Description("Content of the note")] string content) =>
        {
            noteStore.AddNote(title, content);
            return $"Note saved: '{title}'";
        },
        "take_note",
        "Saves a research note with a title and content for later reference."),

    AIFunctionFactory.Create(
        () => noteStore.GetAllNotes(),
        "get_notes",
        "Retrieves all research notes taken so far."),
};

const string instructions = """
    You are a research agent. Your job is to research a topic thoroughly by:
    1. Searching the web for relevant information using the web_search tool
    2. Taking notes on key findings using the take_note tool
    3. Performing multiple searches to cover different aspects of the topic
    4. Finally, synthesizing your notes into a comprehensive summary

    Always take notes on important findings before moving to the next search.
    When you have gathered enough information (at least 3 searches), provide a
    final summary that synthesizes all your research notes.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes",
    tools: tools);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}");
Console.WriteLine(new string('─', 50));

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

try
{
    await foreach (var update in agent.RunStreamingAsync(
        $"Research the following topic and provide a comprehensive summary: {topic}",
        options: runOptions))
    {
        if (update.Text is { } text)
        {
            Console.Write(text);
        }
    }

    Console.WriteLine();
    Console.WriteLine(new string('─', 50));
    Console.WriteLine("\n📝 Research Notes Collected:");
    foreach (var note in noteStore.GetAllNotes())
    {
        Console.WriteLine($"  • {note}");
    }
}
catch (Exception ex)
{
    Console.WriteLine($"\nError during research: {ex.Message}");
    Console.WriteLine("Ensure the AI:ApiKey and AI:ModelId are configured (via env vars or appsettings.json).");
}

