+using System.Text.Json;
+using System.Web;
+
+namespace ResearchAgent;
+
+/// <summary>
+/// Provides web search functionality. Uses a simple HTTP-based search
+/// that can be swapped for a dedicated search API (Bing, Google, etc.).
+/// </summary>
+public sealed class WebSearchService
+{
+    private readonly HttpClient _httpClient;
+
+    public WebSearchService()
+    {
+        _httpClient = new HttpClient();
+        _httpClient.DefaultRequestHeaders.Add("User-Agent",
+            "ResearchAgent/1.0 (compatible; research bot)");
+    }
+
+    public async Task<string> SearchAsync(string query)
+    {
+        try
+        {
+            // Use DuckDuckGo instant answer API (no key required)
+            var encoded = HttpUtility.UrlEncode(query);
+            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
+
+            var response = await _httpClient.GetAsync(url);
+            response.EnsureSuccessStatusCode();
+
+            var json = await response.Content.ReadAsStringAsync();
+            var doc = JsonDocument.Parse(json);
+            var root = doc.RootElement;
+
+            var results = new List<string>();
+
+            // Abstract (main summary)
+            if (root.TryGetProperty("Abstract", out var abstractText) &&
+                abstractText.GetString() is { Length: > 0 } abs)
+            {
+                results.Add($"Summary: {abs}");
+            }
+
+            // Related topics
+            if (root.TryGetProperty("RelatedTopics", out var topics) &&
+                topics.ValueKind == JsonValueKind.Array)
+            {
+                foreach (var topic in topics.EnumerateArray().Take(5))
+                {
+                    if (topic.TryGetProperty("Text", out var text) &&
+                        text.GetString() is { Length: > 0 } t)
+                    {
+                        results.Add(t);
+                    }
+                }
+            }
+
+            if (results.Count == 0)
+            {
+                return $"No detailed results found for '{query}'. Try rephrasing the search.";
+            }
+
+            return string.Join("\n\n", results);
+        }
+        catch (HttpRequestException ex)
+        {
+            return $"Search failed: {ex.Message}. The agent should try a different query.";
+        }
+    }
+}
+

